package com.audira.lib.reactnativematerialcolorimport android.content.res.Configurationimport android.os.Buildimport androidx.annotation.RequiresApiimport androidx.compose.material3.dynamicDarkColorSchemeimport androidx.compose.material3.dynamicLightColorSchemeimport com.facebook.react.bridge.ReactApplicationContextimport com.facebook.react.bridge.WritableMapclass AndroidDynamicColorModule(reactApplicationContext: ReactApplicationContext) : NativeAndroidDynamicColorSpec(reactApplicationContext) {  @RequiresApi(Build.VERSION_CODES.S)  override fun getDynamicDarkColorScheme(): WritableMap {    return colorSchemeToWritableMap(dynamicDarkColorScheme(reactApplicationContext))  }  @RequiresApi(Build.VERSION_CODES.S)  override fun getDynamicLightColorScheme(): WritableMap {    return colorSchemeToWritableMap(dynamicLightColorScheme(reactApplicationContext))  }  @RequiresApi(Build.VERSION_CODES.S)  override fun getDynamicColorScheme(): WritableMap {    val isSystemInDarkTheme =      reactApplicationContext.resources.configuration.uiMode and Configuration.UI_MODE_NIGHT_MASK == Configuration.UI_MODE_NIGHT_YES    if(isSystemInDarkTheme) {      return getDynamicDarkColorScheme()    }    return getDynamicLightColorScheme()  }  companion object {    const val NAME = NativeAndroidDynamicColorSpec.NAME  }}